(async function () {
  const resp = await fetch(document.location.href, { method: 'HEAD' });
  const headers = Object.fromEntries(resp.headers.entries());
  const COUNTRY_HEADER_NAME = 'x-geolocation-country';
  const countryHeader =
    headers[COUNTRY_HEADER_NAME] &&
    headers[COUNTRY_HEADER_NAME] !== 'UNKNOWN'
      ? headers[COUNTRY_HEADER_NAME]
      : undefined;
  if (countryHeader) {
    const html = document.documentElement;
    const country = countryHeader
      .trim()
      .toUpperCase()
      .replaceAll(' ', '-');

    const style = document.createElement('style');
    style.innerHTML = ` [data-regionalisation]:not([data-regionalisation~='${country}']){display:none!important}`;
    html.append(style);
  }
})();
